function getImgList(){
    var p = "cp=\"(.*?)\"";
    var str = html.match(p)[1];

    if (str!=null){
        var list = eval("("+window.atob(str)+")").toString().split(",");
        var piclist = new Array([list.length]);
        for (var i = 0; i < list.length; i++) {
            piclist[i] = "http://f.pufei.net/" + list[i];
        }
        return piclist;
    }else {
        return null;
    }

};
